import xml.etree.ElementTree as ET

def parse_xml_config(filepath):
    config = {}
    tree = ET.parse(filepath)
    root = tree.getroot()

    for child in root:
        if child.tag not in config:
            config[child.tag] = {}
        
        if child.text and child.text.strip():
            config[child.tag]['value'] = child.text.strip()

        for attr_name, attr_value in child.attrib.items():
            config[child.tag][attr_name] = attr_value
        
        for sub_child in child:
            if sub_child.tag not in config[child.tag]:
                config[child.tag][sub_child.tag] = {}
            
            if sub_child.text and sub_child.text.strip():
                config[child.tag][sub_child.tag]['value'] = sub_child.text.strip()
            
            for attr_name, attr_value in sub_child.attrib.items():
                config[child.tag][sub_child.tag][attr_name] = attr_value
            
            # Handling deeply nested structures might require recursion,
            # but for typical config files (2-3 levels), this is often sufficient.
            # This example handles up to 2 levels of elements + attributes + text.
            for grand_child in sub_child:
                if grand_child.tag not in config[child.tag][sub_child.tag]:
                    config[child.tag][sub_child.tag][grand_child.tag] = {}
                
                if grand_child.text and grand_child.text.strip():
                    config[child.tag][sub_child.tag][grand_child.tag]['value'] = grand_child.text.strip()
                
                for attr_name, attr_value in grand_child.attrib.items():
                    config[child.tag][sub_child.tag][grand_child.tag][attr_name] = attr_value
                    
    return config